                    <p className="text-sm text-muted-foreground mt-1 leading-relaxed">{step.description}</p>
                  </div>
                </div>
              </AnimatedSection>
            ))}
          </div>

          {/* Terminal */}
          <AnimatedSection delay={0.2}>
            <TerminalPreview lines={terminalLines} />
          </AnimatedSection>
        </div>
      </div>
